\\n\\n// ─── Module state ───────────────────────────────────────────────────────────\\nlet relayLoopGuard: RelayLoopGuard | null = null;\\n\\nexport function getRelayLoopGuard(): RelayLoopGuard | null {\\n  return relayLoopGuard;\\n}\\n\\n// ─── Re-exports from working-state ──────────────────────────────────────────\\nimport {\\n  extractMemoryTokensFromProxy, stripMemoryTokens,\\n  saveDelegationContext, loadDelegationContext,\\n} from \\\"../working-state.js\\\";\\nexport {\\n  extractMemoryTokensFromProxy, stripMemoryTokens,\\n  saveDelegationContext, loadDelegationContext,\\n} from \\\"../working-state.js\\\";\\n\\nexport function notifyRelayOwner(bot: Bot, chatId: number, text: string, context: string): void {\\n  if (!chatId) return;\\n  bot.api.sendMessage(chatId, text).catch((err) => {\\n    console.error(`[relay] owner notification failed (${context}):`, err);\\n  });\\n}\\n\\nexport function buildRelayDelegationPrompt(from: string, d: DelegatePayload, attachmentPath?: string): string {\\n  return (\\n    `[Relay Delegation from \\\"${from}\\\" — id: ${d.id}]\\\\n` +\\n    `你收到一個任務委派，請完成後回傳結果。\\\\n` +\\n    `目標：${d.goal}\\\\n` +\\n    (d.context ? `背景：${d.context}\\\\n` : \\\"\\\") +\\n    (attachmentPath ? `參考檔案：${attachmentPath}\\\\n` : \\\"\\\") +\\n    `如果任務產出了檔案（圖片等），請用 <<RELAY_FILE:${from}|絕對路徑>> 傳回給委派方，再發 RELAY_RESULT。\\\\n` +\\n    `完成時請在回覆中加入：<<RELAY_RESULT:${from}|{\\\"id\\\":\\\"${d.id}\\\",\\\"status\\\":\\\"done\\\",\\\"summary\\\":\\\"...你的摘要...\\\"}>>\\\\n` +\\n    `若無法完成：<<RELAY_RESULT:${from}|{\\\"id\\\":\\\"${d.id}\\\",\\\"status\\\":\\\"failed\\\",\\\"summary\\\":\\\"...原因...\\\"}>>\\\\n` +\\n    `不要加 RELAY_DONE，RELAY_RESULT 會自動結束對話。`\\n  );\\n}\\n\\n\\n// ─── Specialist proxy handler ───────────────────────────────────────────────\\n\\nexport interface ProxyHandlerOpts {\\n  chatId: number;\\n  text: string;\\n  ctx: Context;\\n  session: ChatSession;\\n  streamEditIntervalMs: number;\\n  rateLimitedUntil: number;\\n  parseDuration: (s: string) => number | null;\\n  parseAbsoluteTime: (s: string) => Date | null;\\n  parseRecurrence: (s: string) => any;\\n  computeNextRunAt: (r: any, after?: number) => number | null;\\n  estimateTokens: (x: string | number) => number;\\n}\\n\\n/**\\n * Handle a message when specialist proxy is active.\\n * Returns true if handled (caller should return early), false if not in proxy mode.\\n */\\nexport async function handleSpecialistProxy(opts: ProxyHandlerOpts): Promise<boolean> {\\n  const { chatId, text, ctx, session, streamEditIntervalMs, rateLimitedUntil } = opts;\\n  if (!isProxyActive(chatId)) return false;\\n\\n  const target = getProxyTarget(chatId)!;\\n  try {\\n    const prefix = `🤖 *[${target}]*\\\\n`;\\n    const placeholder = await ctx.reply(`${prefix}Thinking… ▍`, { parse_mode: \\\"Markdown\\\" })\\n      .catch(() => ctx.reply(`🤖 [${target}]\\\\nThinking… ▍`));\\n\\n    let lastEditAt = 0;\\n    let lastRendered = \\\"\\\";\\n    let editTimer: NodeJS.Timeout | null = null;\\n\\n    const editNow = async (content: string) => {\\n      if (rateLimitedUntil > Date.now()) return;\\n      const body = content.length > TG_MAX ? \\\"…\\\" + content.slice(-TG_MAX) : content;\\n      const frame = `${prefix}${body} ▍`;\\n      if (frame === lastRendered) return;\\n      lastRendered = frame;\\n      lastEditAt = Date.now();\\n      try {\\n        await ctx.api.editMessageText(chatId, placeholder.message_id, frame, { parse_mode: \\\"Markdown\\\" });\\n      } catch {\\n        await ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\\\\n${body} ▍`).catch(() => {});\\n      }\\n    };\\n\\n    const onChunk = (currentOutput: string) => {\\n      const stripped = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, \\\"\\\").trim();\\n      if (!stripped) return;\\n      const elapsed = Date.now() - lastEditAt;\\n      if (elapsed >= streamEditIntervalMs) {\\n        editNow(stripped);\\n      } else if (!editTimer) {\\n        editTimer = setTimeout(() => {\\n          editTimer = null;\\n          const latest = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, \\\"\\\").trim();\\n          if (latest) editNow(latest);\\n        }, streamEditIntervalMs - elapsed);\\n      }\\n    };\\n\\n    const { output, proxyDone } = await promptProxy(chatId, text, onChunk, ctx.from?.id);\\n    if (editTimer) { clearTimeout(editTimer); editTimer = null; }\\n\\n    extractMemoryTokensFromProxy(output, ctx.from?.id ?? chatId);\\n\\n    const proxyTokens = transformReplyTokens(output, {\\n      parseDuration: opts.parseDuration,\\n      parseAbsoluteTime: opts.parseAbsoluteTime,\\n      parseRecurrence: opts.parseRecurrence,\\n      computeNextRunAt: opts.computeNextRunAt,\\n    });\\n\\n    if (proxyTokens.sendFiles.length > 0) {\\n      sendFilesByPaths(ctx, proxyTokens.sendFiles).catch((err) =>\\n        console.error(`[specialist:proxy] sendFilesByPaths failed:`, err));\\n    }\\n\\n    for (const emotion of proxyTokens.stickerEmotions) {\\n      const fileId = STICKER_MAP[emotion];\\n      if (fileId) {\\n        ctx.replyWithSticker(fileId).catch((err) =>\\n          console.warn(`[specialist:proxy] STICKER ${emotion} failed:`, (err as Error).message));\\n      }\\n    }\\n\\n    if (proxyTokens.skillUsages.length > 0) {\\n      const skillDir = detectSkillDir();\\n      if (!skillDir.startsWith(\\\"(\\\")) {\\n        for (const u of proxyTokens.skillUsages) {\\n          usageStore.markUsed(skillDir, u.name, u.reason).catch(() => {});\\n        }\\n      }\\n    }\\n\\n    const display = proxyTokens.text.trim();\\n    const proxyStats = getProxyStats(chatId);\\n    const proxyUsage = (() => {\\n      if (!proxyStats) return \\\"\\\";\\n      const inTok = opts.estimateTokens(proxyStats.charsIn);\\n      const outTok = opts.estimateTokens(proxyStats.charsOut);\\n      const totalTok = inTok + outTok;\\n      const limit = config.contextWindowTokens;\\n      const pctStr = limit ? ((totalTok / limit) * 100).toFixed(1) + \\\"%\\\" : \\\"\\\";\\n      return `\\\\n\\\\n— ctx ~${totalTok}/${limit} tok (${pctStr}) • in ${inTok} · out ${outTok}`;\\n    })();\\n\\n    if (display) {\\n      const fullText = `${display}${proxyUsage}`;\\n      const chunks = splitForTelegram(fullText);\\n      const proxyAskKb = buildAskKeyboard(proxyTokens.askTokens);\\n      const first = `${prefix}${chunks[0]}`;\\n      const isLastChunk = chunks.length === 1;\\n      await ctx.api.editMessageText(chatId, placeholder.message_id, first, {\\n        parse_mode: \\\"Markdown\\\",\\n        ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),\\n      }).catch(() => ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\\\\n${chunks[0]}`, {\\n        ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),\\n      }).catch(() => {}));\\n      if (isLastChunk && proxyAskKb) {\\n        askRegistry.set(placeholder.message_id, proxyTokens.askTokens);\\n      }\\n      for (let ci = 1; ci < chunks.length; ci++) {\\n        const isLast = ci === chunks.length - 1;\\n        const msg = await ctx.api.sendMessage(chatId, chunks[ci], {\\n          parse_mode: \\\"Markdown\\\",\\n          ...(isLast && proxyAskKb ? { reply_markup: proxyAskKb } : {}),\\n        }).catch(() => ctx.api.sendMessage(chatId, chunks[ci]).catch(() => null));\\n        if (isLast && proxyAskKb && msg?.message_id) {\\n          askRegistry.set(msg.message_id, proxyTokens.askTokens);\\n        }\\n      }\\n    } else {\\n      await ctx.api.editMessageText(chatId, placeholder.message_id, `${prefix}(no response)`, { parse_mode: \\\"Markdown\\\" }).catch(() => {});\\n    }\\n\\n    if (proxyDone) {\\n      const proxySession = endProxy(chatId);\\n      await ctx.reply(`✅ Specialist \\\"${target}\\\" 完成，已切回主 agent。`);\\n      if (proxySession) {\\n        const summary = buildProxySummary(proxySession);\\n        const userId = ctx.from?.id ?? chatId;\\n        const { runPrompt, sessions } = deps();\\n        const s = await sessions.get(chatId, userId);\\n        const fakeCtx = {\\n          chat: { id: chatId, type: \\\"private\\\" as const },\\n          from: { id: userId, is_bot: false, first_name: \\\"system\\\" },\\n          message: { message_id: 0, date: 0, chat: { id: chatId, type: \\\"private\\\" as const }, text: summary },\\n          api: ctx.api,\\n          reply: (t: string, extra?: any) => ctx.api.sendMessage(chatId, t, extra),\\n        } as unknown as Context;\\n        runPrompt(fakeCtx, s, summary, { kind: \\\"meta\\\" }).catch(() => {});\\n      }\\n    }\\n  } catch (err) {\\n    console.error(`[specialist:proxy] prompt to \\\"${target}\\\" failed:`, err);\\n    await ctx.reply(`⚠️ Specialist \\\"${target}\\\" 回覆失敗：${(err as Error).message}`);\\n  }\\n  return true;\\n}\\n\\n\\n// ─── Specialist pre-filter ──────────────────────────────────────────────────\\n\\n/**\\n * Run local LLM pre-filter to suggest specialist routing.\\n * Returns a hint string to prepend to the prompt, or \\\"\\\" if no match.\\n */\\nexport async function buildSpecialistHint(text: string): Promise<string> {\\n  if (!config.localLlmPrefilter) return \\\"\\\";\\n  try {\\n    const specialists = getSpecialists();\\n    if (specialists.length === 0) return \\\"\\\";\\n    const descs = specialists.map(s => ({\\n      name: s.name,\\n      description: s.name === \\\"slot-dev\\\" ? \\\"UK slot game development with Cocos 3.6.2\\\"\\n        : s.name === \\\"video-prod\\\" ? \\\"Video production, TTS, ffmpeg, sticker pipeline\\\"\\n        : s.name === \\\"researcher\\\" ? \\\"Deep research on any topic (tech, business, science)\\\"\\n        : s.name,\\n    }));\\n    const t0 = Date.now();\\n    const route = await prefilterSpecialistRoute(text, descs);\\n    if (route.target && route.confidence >= 0.85) {\\n      console.log(`[pre-filter] suggesting specialist: ${route.target} (${Date.now() - t0}ms)`);\\n      return (\\n        `[Specialist routing hint — local pre-filter suggests this message belongs to \\\"${route.target}\\\" specialist. ` +\\n        `Consider using <<SPECIALIST_PROXY:${route.target}|${text.slice(0, 100)}>> if appropriate.]\\\\n\\\\n`\\n      );\\n    }\\n    console.log(`[pre-filter] no match (${Date.now() - t0}ms)`);\\n  } catch { /* pre-filter failed — continue without hint */ }\\n  return \\\"\\\";\\n}\\n\\n\\n// ─── Relay token dispatch ───────────────────────────────────────────────────\\n\\nexport interface RelayTokens {\\n  relayTokens: { target: string; text: string }[];\\n  relayFileTokens: { target: string; path: string }[];\\n  relayDelegateTokens: { target: string; payload: DelegatePayload }[];\\n  relayResultTokens: { target: string; payload: ResultPayload }[];\\n  parallelDelegateTasks: ParallelTask[];\\n}\\n\\n/**\\n * Extract relay/delegate/parallel tokens from session buffer.\\n * Mutates session.buffer to strip extracted tokens.\\n */\\nexport function extractRelayTokens(session: ChatSession): RelayTokens {\\n  const relayTokens: { target: string; text: string }[] = [];\\n  const relayFileTokens: { target: string; path: string }[] = [];\\n  const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];\\n  const relayResultTokens: { target: string; payload: ResultPayload }[] = [];\\n  const parallelDelegateTasks: ParallelTask[] = [];\\n\\n  const RELAY_RE = /<<RELAY:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^>\\\\r\\\\n]+?)\\\\s*>>/g;\\n  const RELAY_FILE_RE = /<<RELAY_FILE:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^>\\\\r\\\\n]+?)\\\\s*>>/g;\\n  const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^>\\\\r\\\\n]+?)\\\\s*>>/g;\\n  const RELAY_RESULT_RE = /<<RELAY_RESULT:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*(\\\\{[^>\\\\r\\\\n]+?\\\\})\\\\s*>>/g;\\n  const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^>\\\\r\\\\n]+?)\\\\s*>>/g;\\n\\n  const { masked, restore } = maskCodeRegions(session.buffer);\\n  const stripped = masked\\n    .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {\\n      let p: DelegatePayload;\\n      try {\\n        p = JSON.parse(body) as DelegatePayload;\\n        if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;\\n      } catch {\\n        p = { id: `rd_${Date.now()}`, goal: body.trim() };\\n      }\\n      if (p.goal) relayDelegateTokens.push({ target: target.trim(), payload: p });\\n      return \\\"\\\";\\n    })\\n    .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {\\n      try {\\n        const p = JSON.parse(json) as ResultPayload;\\n        relayResultTokens.push({ target: target.trim(), payload: p });\\n      } catch { /* malformed JSON — ignore */ }\\n      return \\\"\\\";\\n    })\\n    .replace(RELAY_RE, (_m, target: string, msg: string) => {\\n      relayTokens.push({ target: target.trim(), text: msg.trim() });\\n      return \\\"\\\";\\n    })\\n    .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {\\n      relayFileTokens.push({ target: target.trim(), path: p.trim() });\\n      return \\\"\\\";\\n    })\\n    .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {\\n      parallelDelegateTasks.push({\\n        taskId: taskId.trim(),\\n        target: target.trim(),\\n        payload: { id: taskId.trim(), goal: prompt.trim() },\\n      });\\n      return \\\"\\\";\\n    });\\n  session.buffer = restore(stripped);\\n\\n  // Fallback: streaming captures\\n  if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {\\n    const RE2 = /<<RELAY_DELEGATE:\\\\s*([^|>\\\\r\\\\n]+?)\\\\s*\\\\|\\\\s*([^>\\\\r\\\\n]+?)\\\\s*>>/g;\\n    for (const raw of session._streamingDelegates) {\\n      RE2.lastIndex = 0;\\n      const m = RE2.exec(raw);\\n      if (m) {\\n        let p: DelegatePayload;\\n        try {\\n          p = JSON.parse(m[2]) as DelegatePayload;\\n          if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;\\n        } catch {\\n          p = { id: `rd_${Date.now()}`, goal: m[2].trim() };\\n        }\\n        if (p.goal) relayDelegateTokens.push({ target: m[1].trim(), payload: p });\\n      }\\n    }\\n    if (relayDelegateTokens.length > 0) {\\n      console.log(`[relay] delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);\\n    }\\n  }\\n\\n  return { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens, parallelDelegateTasks };\\n}\\n\\n/**\\n * Check and strip <<RELAY_DONE>> from session buffer.\\n */\\nexport function extractRelayDone(session: ChatSession, relayReplyTo: string | undefined): boolean {\\n  const { masked, restore } = maskCodeRegions(session.buffer);\\n  const done = /<<RELAY_DONE>>/i.test(masked);\\n  if (done) {\\n    session.buffer = restore(masked.replace(/<<RELAY_DONE>>/gi, \\\"\\\").trim());\\n    if (relayReplyTo) relayLoopGuard?.markDone(relayReplyTo);\\n  }\\n  return done;\\n}\\n\\n\\n// ─── Relay headless reply dispatch ──────────────────────────────────────────\\n\\nexport interface DispatchRelayOpts {\\n  chatId: number;\\n  ctx: Context;\\n  session: ChatSession;\\n  tokens: RelayTokens;\\n  relayReplyTo: string;\\n  relayDone: boolean;\\n  body: string;\\n  goalContinuationDelayMs: number;\\n}\\n\\n/**\\n * Dispatch relay tokens in headless (relay-reply) mode.\\n * Returns true if handled (caller should return early).\\n */\\nexport function dispatchRelayHeadless(opts: DispatchRelayOpts): boolean {\\n  const { chatId, tokens, relayReplyTo, relayDone, body, goalContinuationDelayMs, ctx, session } = opts;\\n  const { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens } = tokens;\\n\\n  for (const rt of relayTokens) {\\n    sendRelay(rt.target, rt.text).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));\\n  }\\n  for (const rf of relayFileTokens) {\\n    sendRelayFile(rf.target, rf.path, \\\"[RELAY_OUTPUT]\\\").catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));\\n  }\\n  for (const rd of relayDelegateTokens) {\\n    sendRelayDelegate(rd.target, rd.payload).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));\\n  }\\n  for (const rr of relayResultTokens) {\\n    sendRelayResult(rr.target, rr.payload).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));\\n    relayLoopGuard?.markDone(rr.target);\\n  }\\n\\n  const sentExplicitReply = relayTokens.some((rt) => rt.target === relayReplyTo) ||\\n    relayResultTokens.some((rr) => rr.target === relayReplyTo);\\n  const shouldSendAutoReply = !sentExplicitReply && body.trim() !== \\\"\\\" && !relayDone;\\n  if (shouldSendAutoReply) {\\n    sendRelay(relayReplyTo, body).catch((err) =>\\n      console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));\\n  }\\n\\n  console.log(\\n    `[chat ${chatId}] relay reply delivered headlessly to ${relayReplyTo} ` +\\n      `(bufferChars=${session.buffer.length}${relayDone ? \\\", RELAY_DONE\\\" : \\\"\\\"}, autoReply=${shouldSendAutoReply})`,\\n  );\\n\\n  if (relayDone) {\\n    const peer = relayReplyTo;\\n    const privateChatId = config.allowedUserIds[0] ?? 0;\\n    if (privateChatId) {\\n      ctx.api.sendMessage(privateChatId, `✅ 與「${peer}」的 relay 對話結束`).catch(() => {});\\n    }\\n    const { runPrompt, sessions } = deps();\\n    setTimeout(() => {\\n      const summaryPrompt =\\n        `[系統] 你剛才與「${peer}」的 relay 對話已結束。` +\\n        `請用一句話摘要這次 relay 對話的重點，然後呼叫 remember() 存下來。` +\\n        `格式範例：remember(\\\"[relay ${peer}] …摘要內容…\\\")。` +\\n        `不需要回覆其他內容。`;\\n      runPrompt(ctx, session, summaryPrompt, { kind: \\\"meta\\\", silent: true }).catch((err) => {\\n        console.error(`[chat ${chatId}] relay summary meta prompt failed:`, err);\\n      });\\n    }, goalContinuationDelayMs);\\n  }\\n\\n  return true;\\n}\\n\\n\\n// ─── Relay visible-mode dispatch (user-facing turn) ─────────────────────────\\n\\nexport interface DispatchRelayVisibleOpts {\\n  chatId: number;\\n  bot: Bot;\\n  ctx: Context;\\n  session: ChatSession;\\n  tokens: RelayTokens;\\n  relayReplyTo: string | undefined;\\n  relayDone: boolean;\\n  body: string;\\n}\\n\\n/**\\n * Dispatch relay tokens in visible (user-facing) mode.\\n * Fire-and-forget — does not block the reply render.\\n */\\nexport function dispatchRelayVisible(opts: DispatchRelayVisibleOpts): void {\\n  const { chatId, bot, ctx, session, tokens, relayReplyTo, relayDone, body } = opts;\\n  const { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens } = tokens;\\n\\n  if (relayDone) return; // already handled by extractRelayDone\\n\\n  if (relayTokens.length > 0) console.log(`[chat ${chatId}] relay tokens parsed: ${relayTokens.map(t => t.target).join(\\\", \\\")}`);\\n  for (const rt of relayTokens) {\\n    if (!relayReplyTo) relayLoopGuard?.reopen(rt.target);\\n    sendRelay(rt.target, rt.text).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));\\n  }\\n  for (const rf of relayFileTokens) {\\n    sendRelayFile(rf.target, rf.path).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));\\n  }\\n  for (const rd of relayDelegateTokens) {\\n    if (isLocalSpecialist(rd.target)) {\\n      console.log(`[chat ${chatId}] dispatching to local specialist \\\"${rd.target}\\\" (id=${rd.payload.id})`);\\n      saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>\\n        console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));\\n      dispatchToSpecialist(rd.target, rd.payload, ctx.from?.id).then(async (result) => {\\n        console.log(`[chat ${chatId}] specialist \\\"${rd.target}\\\" returned: ${result.payload.status}, summary length=${result.payload.summary?.length ?? 0}`);\\n        saveArtifact(rd.payload.id, rd.target, rd.payload.goal, result.payload.status as any, result.payload.summary, result.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));\\n        const delegationCtx = await loadDelegationContext(rd.payload.id);\\n        const metaPrompt =\\n          delegationCtx +\\n          `[系統] Specialist \\\"${rd.target}\\\" 委派結果回傳\\\\n` +\\n          `Status: ${result.payload.status}\\\\n` +\\n          `Summary:\\\\n${result.payload.summary}\\\\n` +\\n          `[End specialist result]\\\\n\\\\n` +\\n          `請根據委派結果繼續回覆使用者。`;\\n        const userId = config.allowedUserIds[0] ?? chatId;\\n        const { runPrompt, sessions } = deps();\\n        const fakeCtx = {\\n          chat: { id: chatId, type: \\\"private\\\" as const },\\n          from: { id: userId, is_bot: false, first_name: rd.target },\\n          message: { message_id: 0, date: 0, chat: { id: chatId, type: \\\"private\\\" as const }, text: metaPrompt },\\n          api: bot.api,\\n          reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),\\n        } as unknown as Context;\\n        const s = await sessions.get(chatId, userId);\\n        try {\\n          await runPrompt(fakeCtx, s, metaPrompt, { kind: \\\"meta\\\" });\\n        } catch (runErr) {\\n          console.error(`[chat ${chatId}] specialist result injection failed:`, runErr);\\n        }\\n      }).catch((err) => {\\n        console.error(`[chat ${chatId}] specialist dispatch failed:`, err);\\n      });\\n    } else {\\n      if (!relayReplyTo) relayLoopGuard?.reopen(rd.target);\\n      if (session._lastUploadPath) {\\n        const attachmentPath = session._lastUploadPath;\\n        session._lastUploadPath = undefined;\\n        const caption = `${DELEGATE_PREFIX} ${JSON.stringify(rd.payload)}`;\\n        if (caption.length <= 1000) {\\n          sendRelayFile(rd.target, attachmentPath, caption).catch((err) =>\\n            console.error(`[chat ${chatId}] sendRelayFile (delegate attachment) to ${rd.target} failed:`, err));\\n        } else {\\n          sendRelayDelegate(rd.target, rd.payload)\\n            .then(() => sendRelayFile(rd.target, attachmentPath))\\n            .catch((err) =>\\n              console.error(`[chat ${chatId}] relay delegate + attachment fallback to ${rd.target} failed:`, err));\\n        }\\n      } else {\\n        sendRelayDelegate(rd.target, rd.payload).catch((err) =>\\n          console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));\\n      }\\n      if (!relayReplyTo) {\\n        saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>\\n          console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));\\n      }\\n    }\\n  }\\n  for (const rr of relayResultTokens) {\\n    sendRelayResult(rr.target, rr.payload).catch((err) =>\\n      console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));\\n    relayLoopGuard?.markDone(rr.target);\\n  }\\n  if (relayReplyTo && !relayTokens.some((rt) => rt.target === relayReplyTo)) {\\n    sendRelay(relayReplyTo, body).catch((err) =>\\n      console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));\\n  }\\n}\\n\\n// ─── Parallel delegate dispatch ─────────────────────────────────────────────\\n\\nexport function dispatchParallelDelegates(\\n  chatId: number,\\n  bot: Bot,\\n  ctx: Context,\\n  tasks: ParallelTask[],\\n): void {\\n  const validTasks = tasks.filter((t) => isLocalSpecialist(t.target));\\n  const invalidTasks = tasks.filter((t) => !isLocalSpecialist(t.target));\\n  for (const inv of invalidTasks) {\\n    console.warn(`[chat ${chatId}] PARALLEL_DELEGATE unknown specialist: ${inv.target}`);\\n  }\\n  if (validTasks.length === 0) return;\\n\\n  console.log(`[chat ${chatId}] dispatching ${validTasks.length} parallel delegate(s): ${validTasks.map((t) => `${t.target}:${t.taskId}`).join(\\\", \\\")}`);\\n  dispatchParallel(validTasks, ctx.from?.id).then(async (results) => {\\n    console.log(`[chat ${chatId}] parallel dispatch complete: ${results.map((r) => `${r.taskId}=${r.status}`).join(\\\", \\\")}`);\\n    for (const r of results) {\\n      const task = validTasks.find((t) => t.taskId === r.taskId);\\n      saveArtifact(r.taskId, r.target, task?.payload.goal ?? \\\"\\\", r.status, r.summary, r.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));\\n    }\\n    const lines = results.map((r) => {\\n      const statusIcon = r.status === \\\"done\\\" ? \\\"✅\\\" : r.status === \\\"timeout\\\" ? \\\"⏱️\\\" : \\\"❌\\\";\\n      return `[PARALLEL_RESULT:${r.taskId}] ${statusIcon} (${r.target}, ${r.status})\\\\n${r.summary}`;\\n    });\\n    // Cross-check: when ≥2 specialists completed, ask main agent to\\n    // compare findings and flag contradictions before replying to user.\\n    const doneCount = results.filter((r) => r.status === \\\"done\\\").length;\\n    const crossCheckBlock = doneCount >= 2\\n      ? `\\\\n\\\\n[Cross-check 指引]\\\\n` +\\n        `以上有 ${doneCount} 個 specialist 各自獨立完成了任務。回覆使用者前請：\\\\n` +\\n        `1. 比對各結果之間是否有矛盾、衝突或不一致之處\\\\n` +\\n        `2. 若有矛盾，明確指出哪些點衝突並給出你的判斷（採信哪個、為什麼）\\\\n` +\\n        `3. 若無矛盾，整合各結果為統一回覆\\\\n` +\\n        `[End cross-check]\\\\n`\\n      : \\\"\\\";\\n    const metaPrompt =\\n      `[系統] 並行委派結果回傳（${results.length} 個任務全部完成）\\\\n\\\\n` +\\n      lines.join(\\\"\\\\n\\\\n---\\\\n\\\\n\\\") + \\\"\\\\n\\\\n\\\" +\\n      `[End parallel results]` + crossCheckBlock + \\\"\\\\n\\\\n\\\" +\\n      `請根據以上結果繼續回覆使用者。`;\\n    const userId = config.allowedUserIds[0] ?? chatId;\\n    const { runPrompt, sessions } = deps();\\n    const fakeCtx = {\\n      chat: { id: chatId, type: \\\"private\\\" as const },\\n      from: { id: userId, is_bot: false, first_name: \\\"parallel\\\" },\\n      message: { message_id: 0, date: 0, chat: { id: chatId, type: \\\"private\\\" as const }, text: metaPrompt },\\n      api: bot.api,\\n      reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),\\n    } as unknown as Context;\\n    const s = await sessions.get(chatId, userId);\\n    if (s.inflight) {\\n      console.log(`[chat ${chatId}] parallel result queued (session inflight)`);\\n      s._pendingMetaQueue.push({ ctx: fakeCtx, prompt: metaPrompt, opts: { kind: \\\"meta\\\" } });\\n    } else {\\n      try {\\n        await runPrompt(fakeCtx, s, metaPrompt, { kind: \\\"meta\\\" });\\n      } catch (err) {\\n        console.error(`[chat ${chatId}] parallel result injection failed:`, err);\\n      }\\n    }\\n  }).catch((err) => {\\n    console.error(`[chat ${chatId}] parallel dispatch failed:`, err);\\n  });\\n}\\n\\n\\n// ─── Bot handler registration ───────────────────────────────────────────────\\n\\n/**\\n * Register bot-to-bot relay text handler.\\n * Must be called BEFORE the main message:text handler.\\n */\\nexport function setupRelayTextHandler(bot: Bot): void {\\n  bot.on(\\\"message:text\\\", async (ctx, next) => {\\n    if (ctx.chat.type !== \\\"private\\\" || !ctx.from?.is_bot) return next();\\n    console.log(`[relay-debug] bot private msg from ${ctx.from.username ?? ctx.from.id}: \\\"${ctx.message.text.slice(0, 80)}\\\"`);\\n    if (process.env.RELAY_PAUSED === \\\"true\\\") { console.log(\\\"[relay-debug] RELAY_PAUSED, ignoring\\\"); return; }\\n    const parsed = parseBotRelayMessage(ctx.message.text);\\n    if (!parsed) { console.log(\\\"[relay-debug] not relay format, ignoring\\\"); return; }\\n    if (!config.relay) { console.log(\\\"[relay-debug] relay not configured, ignoring\\\"); return; }\\n    if (isDuplicate(parsed.from, parsed.text)) {\\n      console.log(`[relay] dedup: skipping telegram bot-to-bot message from \\\"${parsed.from}\\\"`);\\n      return;\\n    }\\n    console.log(`[relay] ✓ received via TELEGRAM bot-to-bot from \\\"${parsed.from}\\\"`);\\n    const handler = getRelayHandler();\\n    if (handler) handler({ from: parsed.from, text: parsed.text, ts: new Date().toISOString() });\\n  });\\n}\\n\\n/**\\n * Register bot-to-bot relay file (photo/document) handler.\\n * Must be called BEFORE the main file handler.\\n */\\nexport function setupRelayFileHandler(bot: Bot): void {\\n  bot.on([\\\"message:photo\\\", \\\"message:document\\\"], async (ctx, next) => {\\n    if (ctx.chat.type !== \\\"private\\\" || !ctx.from?.is_bot) return next();\\n    if (process.env.RELAY_PAUSED === \\\"true\\\") { console.log(\\\"[relay] RELAY_PAUSED — blocked incoming file\\\"); return; }\\n    if (!config.relay) return;\\n    const ownerChatId = config.allowedUserIds[0];\\n    if (!ownerChatId) return;\\n    const m = ctx.message;\\n    const photo = m.photo?.[m.photo.length - 1];\\n    const fileId = (m.document ?? photo)?.file_id;\\n    if (!fileId) return;\\n    const from = ctx.from.username ?? String(ctx.from.id);\\n    const fileType = photo && !m.document ? \\\"photo\\\" : \\\"document\\\";\\n    const parsedRelayFilePayload = m.caption ? parseRelayPayload(m.caption.trim()) : null;\\n    const isRelayInput = m.caption?.includes(\\\"[RELAY_INPUT]\\\");\\n\\n    // RELAY_DELEGATE with attachment\\n    if (parsedRelayFilePayload?.type === \\\"delegate\\\") {\\n      try {\\n        const d = parsedRelayFilePayload.payload;\\n        const file = await bot.api.getFile(fileId);\\n        const filePath = file.file_path;\\n        if (!filePath) { console.warn(\\\"[relay] RELAY_DELEGATE attachment has no file_path\\\"); return; }\\n        const ext = path.extname(filePath) || (fileType === \\\"photo\\\" ? \\\".jpg\\\" : \\\"\\\");\\n        const ts = new Date().toISOString().replace(/[:.]/g, \\\"-\\\").slice(0, 19);\\n        const localName = `relay-delegate-${from}-${ts}${ext}`;\\n        const uploadsDir = path.join(process.env.ACP_SESSION_CWD || process.cwd(), \\\"uploads\\\");\\n        const localPath = path.join(uploadsDir, localName);\\n        const fileUrl = `https://api.telegram.org/file/bot${bot.token}/${filePath}`;\\n        const resp = await fetch(fileUrl);\\n        if (!resp.ok) { console.error(\\\"[relay] RELAY_DELEGATE attachment download failed:\\\", resp.status); return; }\\n        const buffer = Buffer.from(await resp.arrayBuffer());\\n        await mkdir(uploadsDir, { recursive: true });\\n        await writeFile(localPath, buffer);\\n        console.log(`[relay] ✓ RELAY_DELEGATE attachment saved from \\\"${from}\\\": ${localPath}`);\\n\\n        const userId = config.allowedUserIds[0] ?? 0;\\n        const relayChatId = config.relay!.groupChatId;\\n        notifyRelayOwner(bot, userId, `📋 收到「${from}」的委派任務與附件：${d.goal}`, `delegate attachment from ${from}`);\\n        const relayText = buildRelayDelegationPrompt(from, d, localPath);\\n        const { runPrompt, sessions } = deps();\\n        const fakeCtx = {\\n          chat: { id: relayChatId, type: \\\"supergroup\\\" as const },\\n          from: { id: userId, is_bot: false, first_name: from },\\n          message: { message_id: 0, date: 0, chat: { id: relayChatId, type: \\\"supergroup\\\" as const }, text: relayText },\\n          api: bot.api,\\n          reply: (text: string, extra?: any) => bot.api.sendMessage(relayChatId, text, extra),\\n        } as unknown as Context;\\n        const session = await sessions.get(relayChatId, userId);\\n        await runPrompt(fakeCtx, session, relayText, { kind: \\\"relay\\\", replyTo: from });\\n      } catch (err) {\\n        console.error(`[relay] RELAY_DELEGATE attachment handling failed:`, err);\\n      }\\n      return;\\n    }\\n\\n    // RELAY_INPUT\\n    if (isRelayInput) {\\n      try {\\n        const file = await bot.api.getFile(fileId);\\n        const filePath = file.file_path;\\n        if (!filePath) { console.warn(\\\"[relay] RELAY_INPUT file has no file_path\\\"); return; }\\n        const ext = path.extname(filePath) || (fileType === \\\"photo\\\" ? \\\".jpg\\\" : \\\"\\\");\\n        const ts = new Date().toISOString().replace(/[:.]/g, \\\"-\\\").slice(0, 19);\\n        const localName = `relay-input-${from}-${ts}${ext}`;\\n        const uploadsDir = path.join(process.env.ACP_SESSION_CWD || process.cwd(), \\\"uploads\\\");\\n        const localPath = path.join(uploadsDir, localName);\\n        const fileUrl = `https://api.telegram.org/file/bot${bot.token}/${filePath}`;\\n        const resp = await fetch(fileUrl);\\n        if (!resp.ok) { console.error(\\\"[relay] RELAY_INPUT download failed:\\\", resp.status); return; }\\n        const buffer = Buffer.from(await resp.arrayBuffer());\\n        await mkdir(uploadsDir, { recursive: true });\\n        await writeFile(localPath, buffer);\\n        console.log(`[relay] ✓ RELAY_INPUT saved from \\\"${from}\\\": ${localPath}`);\\n        const { runPrompt, sessions } = deps();\\n        const session = await sessions.get(ownerChatId, ownerChatId);\\n        const prompt =\\n          `[系統] 收到「${from}」透過 relay 傳來的參考圖片（RELAY_INPUT），已存到：${localPath}\\\\n` +\\n          `這是委派任務的參考輸入，不是產出。請在後續生圖時參考此檔案。`;\\n        await runPrompt(\\n          { chat: { id: ownerChatId, type: \\\"private\\\" as const }, from: { id: ownerChatId, is_bot: false, first_name: from }, message: { message_id: 0, date: 0, chat: { id: ownerChatId, type: \\\"private\\\" as const }, text: \\\"\\\" }, api: bot.api, reply: (text: string, extra?: any) => bot.api.sendMessage(ownerChatId, text, extra) } as unknown as Context,\\n          session, prompt, { kind: \\\"meta\\\", silent: true },\\n        );\\n      } catch (err) {\\n        console.error(`[relay] RELAY_INPUT handling failed:`, err);\\n      }\\n      return;\\n    }\\n\\n    // RELAY_OUTPUT\\n    const isRelayOutput = m.caption?.includes(\\\"[RELAY_OUTPUT]\\\");\\n    if (isRelayOutput) {\\n      try {\\n        const file = await bot.api.getFile(fileId);\\n        const filePath = file.file_path;\\n        if (!filePath) { console.warn(\\\"[relay] RELAY_OUTPUT file has no file_path\\\"); return; }\\n        const ext = path.extname(filePath) || (fileType === \\\"photo\\\" ? \\\".jpg\\\" : \\\"\\\");\\n        const ts = new Date().toISOString().replace(/[:.]/g, \\\"-\\\").slice(0, 19);\\n        const localName = `relay-output-${from}-${ts}${ext}`;\\n        const uploadsDir = path.join(process.env.ACP_SESSION_CWD || process.cwd(), \\\"uploads\\\");\\n        const localPath = path.join(uploadsDir, localName);\\n        const fileUrl = `https://api.telegram.org/file/bot${bot.token}/${filePath}`;\\n        const resp = await fetch(fileUrl);\\n        if (!resp.ok) { console.error(\\\"[relay] RELAY_OUTPUT download failed:\\\", resp.status); return; }\\n        const buffer = Buffer.from(await resp.arrayBuffer());\\n        await mkdir(uploadsDir, { recursive: true });\\n        await writeFile(localPath, buffer);\\n        console.log(`[relay] ✓ RELAY_OUTPUT saved from \\\"${from}\\\": ${localPath}`);\\n        const extLower = path.extname(localPath).toLowerCase();\\n        const asPhoto = IMG_EXT.has(extLower) && extLower !== \\\".png\\\" && buffer.length <= 10 * 1024 * 1024;\\n        const caption = `📨 [relay output from ${from}]`;\\n        if (asPhoto) {\\n          await bot.api.sendPhoto(ownerChatId, new InputFile(localPath), { caption });\\n        } else {\\n          await bot.api.sendDocument(ownerChatId, new InputFile(localPath), { caption });\\n        }\\n        console.log(`[relay] ✓ forwarded RELAY_OUTPUT from \\\"${from}\\\" to owner: ${localPath}`);\\n      } catch (err) {\\n        console.error(`[relay] RELAY_OUTPUT handling failed:`, err);\\n      }\\n      return;\\n    }\\n\\n    // Normal relay file: forward to user\\n    const caption = `📨 [relay file from ${from}]${m.caption ? \\\"\\\\n\\\" + m.caption : \\\"\\\"}`;\\n    let sent = false;\\n    try {\\n      if (fileType === \\\"photo\\\") {\\n        await bot.api.sendPhoto(ownerChatId, fileId, { caption });\\n      } else {\\n        await bot.api.sendDocument(ownerChatId, fileId, { caption });\\n      }\\n      sent = true;\\n      console.log(`[relay] ✓ forwarded file from bot \\\"${from}\\\" to owner`);\\n    } catch (err) {\\n      console.error(`[relay] failed to forward file from bot \\\"${from}\\\":`, err);\\n    }\\n    if (sent) {\\n      const { runPrompt, sessions } = deps();\\n      const userId = ownerChatId;\\n      sessions.get(ownerChatId, userId).then((session) => {\\n        const prompt =\\n          `[系統] 收到「${from}」透過 relay 傳來的${fileType === \\\"photo\\\" ? \\\"圖片\\\" : \\\"檔案\\\"}，已自動轉發給使用者。` +\\n          (m.caption ? `\\\\n附帶說明：${m.caption}` : \\\"\\\") +\\n          `\\\\n如果這是委派任務的產出，請告知使用者圖片已送達。`;\\n        runPrompt(\\n          { chat: { id: ownerChatId, type: \\\"private\\\" as const }, from: { id: userId, is_bot: false, first_name: from }, message: { message_id: 0, date: 0, chat: { id: ownerChatId, type: \\\"private\\\" as const }, text: \\\"\\\" }, api: bot.api, reply: (text: string, extra?: any) => bot.api.sendMessage(ownerChatId, text, extra) } as unknown as Context,\\n          session, prompt, { kind: \\\"meta\\\", silent: false },\\n        ).catch((err) => console.error(`[relay] file notify prompt failed:`, err));\\n      }).catch((err) => console.error(\\\"[relay] file notify session get failed:\\\", err));\\n    }\\n  });\\n}\\n\\n\\n// ─── Relay poller initialization ────────────────────────────────────────────\\n\\n/**\\n * Initialize the relay poller (called from main() during startup).\\n */\\nexport function initRelayPoller(bot: Bot): void {\\n  if (!config.relay) return;\\n  const relayConfig = config.relay;\\n  relayLoopGuard = new RelayLoopGuard({\\n    maxTurns: relayConfig.maxConsecutiveTurns,\\n    doneBlockMs: 300_000,\\n  });\\n  startRelayPoller(bot, relayConfig, async (msg) => {\\n    if (relayConfig.transport !== \\\"telegram\\\") ensurePollerRunning();\\n    if (process.env.RELAY_PAUSED === \\\"true\\\") return;\\n    const guard = relayLoopGuard;\\n    if (!guard) return;\\n    const parsedEarly = parseRelayPayload(msg.text);\\n    const isDelegation = parsedEarly?.type === \\\"delegate\\\";\\n    const decision = guard.allowIncoming(msg.from);\\n    if (decision.action === \\\"blocked-done\\\" && !isDelegation) {\\n      console.log(`[relay] done guard: skipping inject from \\\"${msg.from}\\\" until ${new Date(decision.until).toISOString()}`);\\n      const peer = msg.from;\\n      const chatId = relayConfig.groupChatId;\\n      const userId = config.allowedUserIds[0] ?? 0;\\n      const { runPrompt, sessions } = deps();\\n      sessions.get(chatId, userId).then((session) => {\\n        const fakeCtx = {\\n          chat: { id: chatId, type: \\\"supergroup\\\" as const },\\n          from: { id: userId, is_bot: false, first_name: peer },\\n          message: { message_id: 0, date: 0, chat: { id: chatId, type: \\\"supergroup\\\" as const }, text: \\\"\\\" },\\n          api: bot.api,\\n          reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),\\n        } as unknown as Context;\\n        const summaryPrompt =\\n          `[系統] 你剛才與「${peer}」的 relay 對話已結束（對方先發了 RELAY_DONE）。` +\\n          `請用一句話摘要這次 relay 對話的重點，然後呼叫 remember() 存下來。` +\\n          `格式範例：remember(\\\"[relay ${peer}] …摘要內容…\\\")。` +\\n          `不需要回覆其他內容。`;\\n        runPrompt(fakeCtx, session, summaryPrompt, { kind: \\\"meta\\\", silent: true }).catch((err) => {\\n          console.error(`[relay] peer-done remember meta prompt failed:`, err);\\n        });\\n      }).catch((err) => console.error(\\\"[relay] peer-done session get failed:\\\", err));\\n      return;\\n    }\\n    if (decision.action === \\\"blocked-max\\\") {\\n      console.log(`[relay] idle-loop guard: ${decision.turns}/${decision.maxTurns} consecutive turns, permanently blocked from \\\"${msg.from}\\\"`);\\n      const privateChatId = config.allowedUserIds[0] ?? 0;\\n      if (privateChatId) {\\n        bot.api.sendMessage(privateChatId, `⚠️ 與「${msg.from}」的 rel