  <outcome>"{\"type\":\"text\",\"file\":{\"filePath\":\"G:\\\\AI\\\\telegram-kiro-bridge-main\\\\src\\\\specialist.ts\",\"content\":\"/**\\n * Specialist — local agent instances (same machine, stdio AcpClient).\\n *\\n * Config lives at AGENT_CONFIG_DIR/specialists.json. Each entry defines\\n * a named specialist with its own CLI harness, working directory, and\\n * user-data-dir for skill isolation.\\n *\\n * Flow:\\n *   1. Bridge intercepts RELAY_DELEGATE token\\n *   2. If target matches a specialist name → dispatch here (not relay)\\n *   3. Spawn or reuse an AcpClient for that specialist\\n *   4. Inject goal prompt → collect result → return ResultPayload\\n */\\nimport { readFile } from \\\"node:fs/promises\\\";\\nimport { appendFile, mkdir } from \\\"node:fs/promises\\\";\\nimport path from \\\"node:path\\\";\\nimport { AcpClient, type AcpClientOptions, type SessionUpdate } from \\\"./acpClient.js\\\";\\nimport type { DelegatePayload, ResultPayload } from \\\"./relay.js\\\";\\nimport { config } from \\\"./config.js\\\";\\nimport { buildSpecialistPreamble, getSpecialistScope } from \\\"./specialist-create.js\\\";\\nimport { runEnrichment } from \\\"./enrichment.js\\\";\\nimport { isEmbedRouterReady } from \\\"./embed-router.js\\\";\\nimport { isWikiRetrievalReady } from \\\"./wiki-retrieval.js\\\";\\nimport { isMemoryRecallReady } from \\\"./memory-recall.js\\\";\\nimport { registerTask, updateTask, completeTask } from \\\"./status-store.js\\\";\\nimport { broadcastSSE } from \\\"./status-server.js\\\";\\n\\n// ─── Config types ──────────────────────────────────────────────────────────\\n\\nexport interface SpecialistHarness {\\n  command: string;\\n  args: string[];\\n}\\n\\nexport interface SpecialistEntry {\\n  /** Display/lookup name — must match the target in RELAY_DELEGATE token. */\\n  name: string;\\n  /** CLI command + args to spawn the agent. */\\n  harness: SpecialistHarness;\\n  /** Working directory for the specialist session. */\\n  cwd: string;\\n  /** Extra env vars merged into the specialist process. */\\n  env?: Record<string, string>;\\n  /** MCP servers to inject via ACP session/new. */\\n  mcpServers?: any[];\\n  /** Max turns before force-stopping a delegation. Default 15. */\\n  maxTurns?: number;\\n  /** Timeout (ms) for the entire delegation. Default 600000 (10min). */\\n  timeoutMs?: number;\\n}\\n\\nexport type SpecialistsConfig = SpecialistEntry[];\\n\\n// ─── Config loading ────────────────────────────────────────────────────────\\n\\nlet loadedConfig: SpecialistsConfig = [];\\nlet configPath = \\\"\\\";\\n\\nexport function getSpecialists(): SpecialistsConfig {\\n  return loadedConfig;\\n}\\n\\n/** Check if a target name matches a local specialist. */\\nexport function isLocalSpecialist(target: string): boolean {\\n  return loadedConfig.some((s) => s.name === target);\\n}\\n\\n/** Check if harness uses --agent flag (kiro-cli loads MCP servers from agent config). */\\nfunction harnessHasAgentFlag(entry: SpecialistEntry): boolean {\\n  return entry.harness.args.includes(\\\"--agent\\\");\\n}\\n\\n/** Expand ${MEMORY_DIR} / ${AGENT_CONFIG_DIR} / ${BRIDGE_DIR} in specialist config strings. */\\nfunction expandVars(entry: SpecialistEntry): SpecialistEntry {\\n  const vars: Record<string, string> = {\\n    MEMORY_DIR: config.memoryDir,\\n    AGENT_CONFIG_DIR: path.dirname(configPath),\\n    BRIDGE_DIR: path.resolve(config.sessionCwd),\\n  };\\n  const replace = (s: string) =>\\n    s.replace(/\\\\$\\\\{(\\\\w+)\\\\}/g, (_, k) => vars[k] ?? `\\\\${${k}}`);\\n  return {\\n    ...entry,\\n    cwd: replace(entry.cwd),\\n    harness: { command: entry.harness.command, args: entry.harness.args.map(replace) },\\n    env: entry.env\\n      ? Object.fromEntries(Object.entries(entry.env).map(([k, v]) => [k, replace(v)]))\\n      : undefined,\\n  };\\n}\\n\\n/** Load specialists.json from AGENT_CONFIG_DIR. Returns count loaded. */\\nexport async function loadSpecialistsConfig(agentConfigDir: string): Promise<number> {\\n  configPath = path.join(agentConfigDir, \\\"specialists.json\\\");\\n  try {\\n    const raw = await readFile(configPath, \\\"utf8\\\");\\n    const parsed = JSON.parse(raw);\\n    if (!Array.isArray(parsed)) {\\n      console.warn(`[specialist] ${configPath} is not an array, ignoring`);\\n      loadedConfig = [];\\n      return 0;\\n    }\\n    loadedConfig = (parsed as SpecialistsConfig).map(expandVars);\\n    console.log(`[specialist] loaded ${loadedConfig.length} specialist(s) from ${configPath}`);\\n    return loadedConfig.length;\\n  } catch (err: any) {\\n    if (err.code === \\\"ENOENT\\\") {\\n      console.log(`[specialist] no config at ${configPath} — feature disabled`);\\n    } else {\\n      console.warn(`[specialist] failed to load ${configPath}:`, err.message);\\n    }\\n    loadedConfig = [];\\n    return 0;\\n  }\\n}\\n\\n// ─── Transcript persistence ────────────────────────────────────────────────\\n\\nconst transcriptDir = path.join(config.memoryDir, \\\"sessions\\\");\\n\\nasync function appendTranscript(name: string, role: \\\"user\\\" | \\\"assistant\\\", text: string): Promise<void> {\\n  const date = new Date().toISOString().slice(0, 10);\\n  const file = path.join(transcriptDir, `specialist-${name}-${date}.md`);\\n  await mkdir(transcriptDir, { recursive: true });\\n  const prefix = role === \\\"user\\\" ? \\\"**User:**\\\" : `**${name}:**`;\\n  const entry = `${prefix}\\\\n${text}\\\\n\\\\n---\\\\n\\\\n`;\\n  await appendFile(file, entry, \\\"utf8\\\");\\n}\\n\\n// ─── Instance management ───────────────────────────────────────────────────\\n\\ninterface LiveInstance {\\n  client: AcpClient;\\n  busy: boolean;\\n  sessionId: string;\\n}\\n\\nconst instances = new Map<string, LiveInstance>();\\n\\nfunction getEntry(name: string): SpecialistEntry | undefined {\\n  return loadedConfig.find((s) => s.name === name);\\n}\\n\\n/** Close and remove a specialist instance. */\\nexport function closeInstance(name: string): void {\\n  const inst = instances.get(name);\\n  if (inst) {\\n    inst.client.close();\\n    instances.delete(name);\\n    console.log(`[specialist:${name}] closed (task done)`);\\n  }\\n}\\n\\n/** Close a parallel instance by its unique instanceId. */\\nexport function closeParallelInstance(instanceId: string): void {\\n  const inst = parallelInstances.get(instanceId);\\n  if (inst) {\\n    inst.client.close();\\n    parallelInstances.delete(instanceId);\\n    console.log(`[specialist:${instanceId}] parallel instance closed`);\\n  }\\n}\\n\\n/** Parallel instances — keyed by unique instanceId, not reused. */\\nconst parallelInstances = new Map<string, LiveInstance>();\\n\\n/** Spawn a fresh instance (no reuse). Returns a unique instanceId. */\\nexport async function spawnNew(name: string): Promise<{ instanceId: string; inst: LiveInstance }> {\\n  const entry = getEntry(name);\\n  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);\\n\\n  const instanceId = `${name}-${Math.random().toString(16).slice(2, 6)}`;\\n\\n  const opts: AcpClientOptions = {\\n    command: entry.harness.command,\\n    args: [...entry.harness.args],\\n    cwd: path.resolve(entry.cwd),\\n    env: { MEMORY_DIR: config.memoryDir, ...entry.env },\\n    promptRetries: 2,\\n    promptRetryBaseMs: 1000,\\n  };\\n\\n  const client = new AcpClient(opts);\\n  client.on(\\\"stderr\\\", (chunk) => {\\n    process.stderr.write(`[specialist:${instanceId}] ${chunk}`);\\n  });\\n  client.on(\\\"exit\\\", (code) => {\\n    console.log(`[specialist:${instanceId}] process exited (code=${code})`);\\n    parallelInstances.delete(instanceId);\\n  });\\n\\n  // If harness uses --agent flag, kiro-cli loads MCP servers from its own\\n  // agent config — passing them again in session/new causes a crash.\\n  const mcpServers = harnessHasAgentFlag(entry) ? undefined : entry.mcpServers;\\n  const sessionId = await client.initializeAndCreateSession(opts.cwd, mcpServers);\\n  const inst: LiveInstance = { client, busy: false, sessionId };\\n  parallelInstances.set(instanceId, inst);\\n  console.log(`[specialist:${instanceId}] spawned (parallel), session=${sessionId}`);\\n  return { instanceId, inst };\\n}\\n\\nasync function spawnOrReuse(name: string): Promise<LiveInstance> {\\n  const existing = instances.get(name);\\n  if (existing && !existing.client.isClosed) return existing;\\n\\n  // Clean up stale entry\\n  if (existing) instances.delete(name);\\n\\n  const entry = getEntry(name);\\n  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);\\n\\n  const opts: AcpClientOptions = {\\n    command: entry.harness.command,\\n    args: [...entry.harness.args],\\n    cwd: path.resolve(entry.cwd),\\n    env: { MEMORY_DIR: config.memoryDir, ...entry.env },\\n    promptRetries: 2,\\n    promptRetryBaseMs: 1000,\\n  };\\n\\n  const client = new AcpClient(opts);\\n  client.on(\\\"stderr\\\", (chunk) => {\\n    process.stderr.write(`[specialist:${name}] ${chunk}`);\\n  });\\n  client.on(\\\"exit\\\", (code) => {\\n    console.log(`[specialist:${name}] process exited (code=${code})`);\\n    instances.delete(name);\\n  });\\n\\n  const sessionId = await client.initializeAndCreateSession(opts.cwd,\\n    harnessHasAgentFlag(entry) ? undefined : entry.mcpServers);\\n  const inst: LiveInstance = { client, busy: false, sessionId };\\n  instances.set(name, inst);\\n  console.log(`[specialist:${name}] spawned, session=${sessionId}`);\\n  return inst;\\n}\\n\\n// ─── Dispatch ──────────────────────────────────────────────────────────────\\n\\nexport interface DispatchResult {\\n  payload: ResultPayload;\\n  /** Raw text chunks collected from the specialist's response. */\\n  rawOutput: string;\\n}\\n\\n/**\\n * Dispatch a delegation to a local specialist.\\n * Spawns/reuses the specialist, sends the goal prompt, collects the response,\\n * and returns a structured ResultPayload.\\n */\\nexport async function dispatchToSpecialist(\\n  target: string,\\n  delegate: DelegatePayload,\\n  userId?: number,\\n): Promise<DispatchResult> {\\n  const entry = getEntry(target);\\n  if (!entry) throw new Error(`[specialist] unknown: ${target}`);\\n\\n  const inst = await spawnOrReuse(target);\\n  if (inst.busy) {\\n    return {\\n      payload: { id: delegate.id, status: \\\"failed\\\", summary: \\\"Specialist is busy with another task\\\" },\\n      rawOutput: \\\"\\\",\\n    };\\n  }\\n\\n  inst.busy = true;\\n  const maxTurns = delegate.maxTurns ?? entry.maxTurns ?? 15;\\n  const timeoutMs = entry.timeoutMs ?? 600_000;\\n\\n  // Register with status store\\n  registerTask({\\n    taskId: delegate.id,\\n    type: \\\"specialist\\\",\\n    specialist: target,\\n    goal: delegate.goal.slice(0, 100),\\n  });\\n\\n  // Build preamble from relevant topic shards\\n  const preamble = await buildSpecialistPreamble(target, userId ?? 0).catch(() => \\\"\\\");\\n\\n  // Run scoped enrichment based on the delegation goal\\n  const scope = await getSpecialistScope(target).catch(() => undefined);\\n  const enrichment = await runEnrichment(delegate.goal, userId ?? 0, undefined, scope).catch(() => \\\"\\\");\\n\\n  // Build the goal prompt\\n  const prompt = buildGoalPrompt(delegate, preamble, enrichment);\\n\\n  let output = \\\"\\\";\\n  const updateHandler = (u: SessionUpdate) => {\\n    const up = u.update;\\n    if (\\n      (up.sessionUpdate === \\\"agent_message_chunk\\\" || up.sessionUpdate === \\\"agent_thought_chunk\\\") \\n    ) {\\n      const content = up.content as { type?: string; text?: string } | undefined;\\n      if (content?.type === \\\"text\\\" && typeof content.text === \\\"string\\\") {\\n        output += content.text;\\n        const role = up.sessionUpdate === \\\"agent_thought_chunk\\\" ? \\\"thought\\\" : \\\"agent\\\";\\n        broadcastSSE(delegate.id, { type: \\\"chunk\\\", role, text: content.text });\\n      }\\n    }\\n  };\\n  inst.client.on(\\\"update\\\", updateHandler);\\n\\n  try {\\n    // Multi-turn loop: keep prompting until agent says done or budget exhausted\\n    let turns = 0;\\n    let lastStopReason = \\\"\\\";\\n\\n    const deadline = Date.now() + timeoutMs;\\n\\n    while (turns < maxTurns && Date.now() < deadline) {\\n      turns++;\\n      updateTask(delegate.id, { turns, lastOutput: output.slice(-200) || undefined });\\n      broadcastSSE(delegate.id, { type: \\\"status\\\", status: \\\"running\\\", turns });\\n      const promptText = turns === 1 ? prompt : \\\"[系統] 繼續執行，完成後在回覆中說明結果。\\\";\\n\\n      const result = await Promise.race([\\n        inst.client.prompt(promptText),\\n        new Promise<never>((_, reject) =>\\n          setTimeout(() => reject(new Error(\\\"timeout\\\")), Math.max(1000, deadline - Date.now())),\\n        ),\\n      ]);\\n\\n      lastStopReason = result.stopReason;\\n      // If agent stopped normally (end_turn), check if it needs more turns\\n      if (lastStopReason === \\\"end_turn\\\" || lastStopReason === \\\"stop\\\") break;\\n      // tool_use means agent is still working — loop for next turn\\n    }\\n\\n    // Extract summary from output (last 2000 chars as summary)\\n    const summary = output.length > 2000 ? output.slice(-2000) : output || \\\"(no output)\\\";\\n\\n    const status: ResultPayload[\\\"status\\\"] =\\n      Date.now() >= deadline ? \\\"timeout\\\" : \\\"done\\\";\\n\\n    completeTask(delegate.id, status, { lastOutput: summary.slice(0, 200) });\\n    broadcastSSE(delegate.id, { type: \\\"status\\\", status });\\n\\n    // Persist transcript for /memorytoskill\\n    appendTranscript(target, \\\"user\\\", prompt).catch(() => {});\\n    appendTranscript(target, \\\"assistant\\\", output).catch(() => {});\\n\\n    return {\\n      payload: { id: delegate.id, status, summary },\\n      rawOutput: output,\\n    };\\n  } catch (err: any) {\\n    const msg = err.message ?? String(err);\\n    const failStatus = msg.includes(\\\"timeout\\\") ? \\\"timeout\\\" : \\\"failed\\\";\\n    completeTask(delegate.id, failStatus, { err