       if (result.stopReason === \\\"end_turn\\\" || result.stopReason === \\\"stop\\\") break;\\n        }\\n\\n        const summary = output.length > 2000 ? output.slice(-2000) : output || \\\"(no output)\\\";\\n        const status: ParallelResult[\\\"status\\\"] = Date.now() >= deadline ? \\\"timeout\\\" : \\\"done\\\";\\n\\n        completeTask(task.taskId, status, { lastOutput: summary.slice(0, 200) });\\n\\n        appendTranscript(task.target, \\\"user\\\", prompt).catch(() => {});\\n        appendTranscript(task.target, \\\"assistant\\\", output).catch(() => {});\\n\\n        return { taskId: task.taskId, target: task.target, status, summary, rawOutput: output };\\n      } finally {\\n        inst.client.removeListener(\\\"update\\\", updateHandler);\\n        closeParallelInstance(instanceId);\\n      }\\n    } catch (err: any) {\\n      if (instanceId) closeParallelInstance(instanceId);\\n      const msg = (err.message ?? String(err)).slice(0, 500);\\n      completeTask(task.taskId, \\\"failed\\\", { error: msg.slice(0, 200) });\\n      return { taskId: task.taskId, target: task.target, status: \\\"failed\\\", summary: `Error: ${msg}`, rawOutput: \\\"\\\" };\\n    }\\n  });\\n\\n  const settled = await Promise.allSettled(promises);\\n  return settled.map((s, i) =>\\n    s.status === \\\"fulfilled\\\"\\n      ? s.value\\n      : { taskId: tasks[i].taskId, target: tasks[i].target, status: \\\"failed\\\" as const, summary: `Unexpected: ${s.reason}`, rawOutput: \\\"\\\" },\\n  );\\n}\\n\\n// ─── Cleanup ───────────────────────────────────────────────────────────────\\n\\nexport async function shutdownAllSpecialists(): Promise<void> {\\n  for (const [name, inst] of instances) {\\n    console.log(`[specialist:${name}] shutting down...`);\\n    await inst.client.close();\\n  }\\n  instances.clear();\\n  proxyState.clear();\\n}\\n\\n// ─── Transparent Proxy Mode ────────────────────────────────────────────────\\n\\nconst PROXY_DONE_RE = /<<PROXY_DONE>>/i;\\n\\ninterface ProxySession {\\n  specialistName: string;\\n  /** Conversation history for end-of-proxy summary. */\\n  history: { role: \\\"user\\\" | \\\"assistant\\\"; text: string }[];\\n  startedAt: number;\\n  lastActivity: number;\\n  /** Facts already injected via enrichment — dedup across turns. */\\n  injectedFacts: Set<string>;\\n  /** Total chars sent to specialist (preamble + enrichment + user text). */\\n  charsIn: number;\\n  /** Total chars received from specialist. */\\n  charsOut: number;\\n}\\n\\nconst proxyState = new Map<number, ProxySession>();\\n\\n/** Check if a chatId is currently in proxy mode. */\\nexport function isProxyActive(chatId: number): boolean {\\n  return proxyState.has(chatId);\\n}\\n\\n/** Get the active proxy specialist name for a chatId. */\\nexport function getProxyTarget(chatId: number): string | undefined {\\n  return proxyState.get(chatId)?.specialistName;\\n}\\n\\n/** Get cumulative char stats for the active proxy session. */\\nexport function getProxyStats(chatId: number): { charsIn: number; charsOut: number } | undefined {\\n  const ps = proxyState.get(chatId);\\n  return ps ? { charsIn: ps.charsIn, charsOut: ps.charsOut } : undefined;\\n}\\n\\n/** Enter proxy mode: subsequent user messages go directly to this specialist. */\\nexport function startProxy(chatId: number, specialistName: string): void {\\n  proxyState.set(chatId, {\\n    specialistName,\\n    history: [],\\n    startedAt: Date.now(),\\n    lastActivity: Date.now(),\\n    injectedFacts: new Set(),\\n    charsIn: 0,\\n    charsOut: 0,\\n  });\\n  console.log(`[specialist:proxy] chat ${chatId} → proxy to \\\"${specialistName}\\\"`);\\n}\\n\\n/** Exit proxy mode. Returns the conversation history for summary injection. */\\nexport function endProxy(chatId: number): ProxySession | undefined {\\n  const session = proxyState.get(chatId);\\n  proxyState.delete(chatId);\\n  if (session) {\\n    console.log(`[specialist:proxy] chat ${chatId} exited proxy (${session.history.length} exchanges)`);\\n    closeInstance(session.specialistName);\\n  }\\n  return session;\\n}\\n\\n/** Register a callback for idle timeout auto-exit. */\\n/**\\n * Send a user message to the proxied specialist and collect the response.\\n * Returns the raw output text (caller is responsible for sending to Telegram\\n * and extracting memory tokens).\\n */\\nexport async function promptProxy(\\n  chatId: number,\\n  text: string,\\n  onChunk?: (currentOutput: string) => void,\\n  userId?: number,\\n): Promise<{ output: string; stopReason: string; proxyDone: boolean }> {\\n  const ps = proxyState.get(chatId);\\n  if (!ps) throw new Error(\\\"[specialist:proxy] no active proxy for this chat\\\");\\n\\n  const inst = await spawnOrReuse(ps.specialistName);\\n\\n  // First prompt: prepend preamble + instruction so specialist knows about PROXY_DONE\\n  const isFirst = ps.history.length === 0;\\n  let prompt: string;\\n  if (isFirst) {\\n    const preamble = await buildSpecialistPreamble(ps.specialistName, userId ?? 0, { proxy: true }).catch(() => \\\"\\\");\\n    // Run scoped enrichment for the first message too\\n    const scope = await getSpecialistScope(ps.specialistName).catch(() => undefined);\\n    console.log(`[specialist:proxy] enrichment scope for ${ps.specialistName}:`, JSON.stringify(scope ?? null));\\n    console.log(`[specialist:proxy] subsystem ready: embed=${isEmbedRouterReady()}, wiki=${isWikiRetrievalReady()}, recall=${isMemoryRecallReady()}`);\\n    const enrichment = await runEnrichment(text, userId ?? 0, ps.injectedFacts, scope).catch((e) => { console.warn(\\\"[specialist:proxy] enrichment error:\\\", e); return \\\"\\\"; });\\n    console.log(`[specialist:proxy] enrichment result length: ${enrichment.length}${enrichment.length > 0 ? \\\" (has content)\\\" : \\\" (empty)\\\"}`);\\n    prompt = `${preamble}[System] You are in a proxy conversation with the user. Do NOT append <<PROXY_DONE>> unless the user explicitly ends the conversation (says goo