eanOutput = output.replace(PROXY_DONE_RE, \\\"\\\").trim();\\n    return { output: cleanOutput, stopReason: result.stopReason, proxyDone };\\n  } finally {\\n    inst.client.removeListener(\\\"update\\\", updateHandler);\\n  }\\n}\\n\\n/** Build a summary of the proxy conversation for injection into main agent. */\\nexport function buildProxySummary(session: ProxySession): string {\\n  const lines: string[] = [];\\n  const count = Math.floor(session.history.length / 2);\\n  // Keep last 5 exchanges max for summary\\n  const recent = session.history.slice(-10);\\n  for (const h of recent) {\\n    const prefix = h.role === \\\"user\\\" ? \\\"User\\\" : session.specialistName;\\n    const truncated = h.text.length > 300 ? h.text.slice(0, 300) + \\\"…\\\" : h.text;\\n    lines.push(`${prefix}: ${truncated}`);\\n  }\\n  return (\\n    `[系統] Specialist \\\"${session.specialistName}\\\" proxy 結束（共 ${count} 輪對話）\\\\n` +\\n    `以下是最近的對話摘要：\\\\n` +\\n    lines.join(\\\"\\\\n\\\") + \\\"\\\\n\\\" +\\n    `[End proxy summary]\\\\n\\\\n` +\\n    `使用者已切回跟你對話。如果 specialist 的工作有後續，請接續處理。`\\n  );\\n}\\n\",\"numLines\":648,\"startLine\":1,\"totalLines\":648}}"</outcome>
